gpu_trend_hitmap.mqlTemplate:
kv.load {table: stat_gpu_trend_hitmap-{{epoch}}}
FILTER {key: t, over: {{stime}}}
FILTER {key: t, under: {{etime}}}
SELECT [t, UUID, value, max_value, min_value]
UNFOLD [UUID, value, max_value, min_value]
RENAME {src:value, dst:avg_value}
JOIN {query: label_info, pk: UUID, type: inner}
SUB label_info
>> match DCGM_FI_DEV_WEIGHTED_GPU_UTIL
LAST-ONLY [UUID]
END

